# Configuration from environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
STORAGE_CONTAINER_NAME = os.environ.get("STORAGE_CONTAINER_NAME", "input-files")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "processing-db")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENTGRID_ENDPOINT = os.environ.get("EVENTGRID_ENDPOINT", "https://<topic>.eventgrid.azure.net/api/events")
MANAGED_IDENTITY_CLIENT_ID = os.environ.get("MANAGED_IDENTITY_CLIENT_ID", None)

app = func.FunctionApp()


def get_credential():
    """
    Get Azure credential using Managed Identity.
    
    SECURITY NOTE: This MVP uses broad permissions for rapid development:
    - Storage Blob Data Contributor (read/write/delete blobs)
    - Cosmos DB Account Contributor (full Cosmos DB access)
    - Event Grid Data Sender (publish events)
    
    For production, follow the principle of least privilege:
    - Use Storage Blob Data Reader if only reading blobs
    - Use a custom Cosmos DB role with minimal data-plane permissions
    - Scope permissions to specific resources, not resource groups
    - Consider using separate managed identities per resource
    """
    if MANAGED_IDENTITY_CLIENT_ID:
        # Use user-assigned managed identity
        return ManagedIdentityCredential(client_id=MANAGED_IDENTITY_CLIENT_ID)
    else:
        # Use system-assigned managed identity (or local dev credentials)
        return DefaultAzureCredential()


def get_blob_service_client() -> BlobServiceClient:
    """Create a BlobServiceClient using Managed Identity."""
    credential = get_credential()
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)


def get_cosmos_client() -> CosmosClient:
    """Create a CosmosClient using Managed Identity."""
    credential = get_credential()
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)


def get_eventgrid_client() -> EventGridPublisherClient:
    """Create an EventGridPublisherClient using Managed Identity."""
    credential = get_credential()
    return EventGridPublisherClient(endpoint=EVENTGRID_ENDPOINT, credential=credential)


def ensure_cosmos_database_and_container(cosmos_client: CosmosClient):
    """Ensure Cosmos DB database and container exist."""
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path="/partitionKey"),
        offer_throughput=400
    )
    return database, container


def process_blob_content(blob_name: str, content: bytes) -> Dict[str, Any]:
    """
    Process the blob content and return structured results.
    
    This is where your business logic goes. For this MVP,
    we parse JSON files and extract summary information.
    """
    result = {
        "id": blob_name.replace("/", "_").replace(".", "_"),
        "partitionKey": "processed",
        "sourceBlobName": blob_name,
        "processedAt": datetime.datetime.utcnow().isoformat(),
        "status": "success",
        "contentSizeBytes": len(content),
    }

    try:
        # Attempt to parse as JSON
        data = json.loads(content.decode("utf-8"))
        result["dataType"] = "json"
        result["recordCount"] = len(data) if isinstance(data, list) else 1
        result["summary"] = {
            "keys": list(data.keys()) if isinstance(data, dict) else None,
            "itemCount": len(data) if isinstance(data, (list, dict)) else None,
        }
    except (json.JSONDecodeError, UnicodeDecodeError):
        # Handle non-JSON content (CSV, text, binary, etc.)
        try:
            text_content = content.decode("utf-8")
            lines = text_content.strip().split("\n")
            result["dataType"] = "text"
            result["recordCount"] = len(lines)
            result["summary"] = {
                "lineCount": len(lines),
                "firstLine": lines[0][:200] if lines else None,
            }
        except UnicodeDecodeError:
            result["dataType"] = "binary"
            result["recordCount"] = 0
            result["summary"] = {
                "note": "Binary file detected, no text parsing performed"
            }

    return result


def send_event_notification(
    eventgrid_client: EventGridPublisherClient,
    blob_name: str,
    processing_result: Dict[str, Any],
    event_type: str = "FileProcessing.Completed"
):
    """Send a notification via Event Grid about the processing result."""
    event = CloudEvent(
        type=event_type,
        source=f"/azure/functions/blob-processor",
        data={
            "blobName": blob_name,
            "status": processing_result.get("status", "unknown"),
            "processedAt": processing_result.get("processedAt"),
            "recordCount": processing_result.get("recordCount", 0),
            "contentSizeBytes": processing_result.get("contentSizeBytes", 0),
            "dataType": processing_result.get("dataType", "unknown"),
            "cosmosDocumentId": processing_result.get("id"),
        },
        subject=f"blobs/{blob_name}",
    )

    eventgrid_client.send([event])
    logging.info(f"Event Grid notification sent for blob: {blob_name}")


@app.blob_trigger(
    arg_name="myblob",
    path=f"{STORAGE_CONTAINER_NAME}/{{name}}",
    connection="AzureWebJobsStorage"
)
def blob_trigger_processor(myblob: func.InputStream):
    """
    Azure Function triggered by new blobs in the input container.
    
    Processes the blob content, writes results to Cosmos DB,
    and sends a notification via Event Grid.
    """
    blob_name = myblob.name
    logging.info(f"Processing blob: {blob_name}, Size: {myblob.length} bytes")

    try:
        # Step 1: Read blob content
        content = myblob.read()
        logging.info(f"Read {len(content)} bytes from blob: {blob_name}")

        # Step 2: Process the content
        processing_result = process_blob_content(blob_name, content)
        logging.info(f"Processing result: {json.dumps(processing_result, default=str)}")

        # Step 3: Write results to Cosmos DB
        cosmos_client = get_cosmos_client()
        database, container = ensure_cosmos_database_and_container(cosmos_client)
        container.upsert_item(processing_result)
        logging.info(f"Results written to Cosmos DB for blob: {blob_name}")

        # Step 4: Send Event Grid notification
        try:
            eventgrid_client = get_eventgrid_client()
            send_event_notification(eventgrid_client, blob_name, processing_result)
        except Exception as eg_error:
            logging.warning(f"Event Grid notification failed (non-fatal): {eg_error}")

        logging.info(f"Successfully processed blob: {blob_name}")

    except Exception as e:
        logging.error(f"Error processing blob {blob_name}: {str(e)}")

        # Attempt to write error record to Cosmos DB
        try:
            error_result = {
                "id": f"error_{blob_name.replace('/', '_').replace('.', '_')}",
                "partitionKey": "errors",
                "sourceBlobName": blob_name,
                "processedAt": datetime.datetime.utcnow().isoformat(),
                "status": "error",
                "errorMessage": str(e),
            }
            cosmos_client = get_cosmos_client()
            _, container = ensure_cosmos_database_and_container(cosmos_client)
            container.upsert_item(error_result)

            # Send error notification
            try:
                eventgrid_client = get_eventgrid_client()
                send_event_notification(
                    eventgrid_client, blob_name, error_result,
                    event_type="FileProcessing.Failed"
                )
            except Exception:
                pass

        except Exception as cosmos_error:
            logging.error(f"Failed to write error record to Cosmos DB: {cosmos_error}")

        raise


@app.route(route="process-blob", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function to manually process a specific blob.
    
    Request body:
    {
        "containerName": "input-files",
        "blobName": "path/to/file.json"
    }
    """
    logging.info("HTTP trigger: Manual blob processing request received")

    try:
        req_body = req.get_json()
        container_name = req_body.get("containerName", STORAGE_CONTAINER_NAME)
        blob_name = req_body.get("blobName")

        if not blob_name:
            return func.HttpResponse(
                json.dumps({"error": "blobName is required in request body"}),
                status_code=400,
                mimetype="application/json"
            )

        # Step 1: Read blob from storage using Managed Identity
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(
            container=container_name, blob=blob_name
        )
        content = blob_client.download_blob().readall()
        logging.info(f"Read {len(content)} bytes from blob: {container_name}/{blob_name}")

        # Step 2: Process the content
        processing_result = process_blob_content(blob_name, content)

        # Step 3: Write results to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_database_and_container(cosmos_client)
        container.upsert_item(processing_result)
        logging.info(f"Results written to Cosmos DB for blob: {blob_name}")

        # Step 4: Send Event Grid notification
        try:
            eventgrid_client = get_eventgrid_client()
            send_event_notification(eventgrid_client, blob_name, processing_result)
        except Exception as eg_error:
            logging.warning(f"Event Grid notification failed (non-fatal): {eg_error}")
            processing_result["eventGridNotification"] = f"failed: {str(eg_error)}"

        return func.HttpResponse(
            json.dumps(processing_result, default=str),
            status_code=200,
            mimetype="application/json"
        )

    except Exception as e:
        logging.error(f"HTTP trigger error: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=500,
            mimetype="application/json"
        )


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint that validates connectivity to all services."""
    health_status = {
        "status": "healthy",
        "timestamp": datetime.datetime.utcnow().isoformat(),
        "services": {}
    }

    # Check Blob Storage connectivity
    try:
        blob_service_client = get_blob_service_client()
        blob_service_client.get_account_information()
        health_status["services"]["blobStorage"] = "connected"
    except Exception as e:
        health_status["services"]["blobStorage"] = f"error: {str(e)}"
        health_status["status"] = "degraded"

    # Check Cosmos DB connectivity
    try:
        cosmos_client = get_cosmos_client()
        list(cosmos_client.list_databases())
        health_status["services"]["cosmosDb"] = "connected"
    except Exception as e:
        health_status["services"]["cosmosDb"] = f"error: {str(e)}"
        health_status["status"] = "degraded"

    # Check Event Grid (basic credential validation)
    try:
        _ = get_eventgrid_client()
        health_status["services"]["eventGrid"] = "client_created"
    except Exception as e:
        health_status["services"]["eventGrid"] = f"error: {str(e)}"
        health_status["status"] = "degraded"

    status_code = 200 if health_status["status"] == "healthy" else 503
    return func.HttpResponse(
        json.dumps(health_status, default=str),
        status_code=status_code,
        mimetype="application/json"
    )


